const input = $json.body || $json;

function sqlQuote(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function intOrNull(value) {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) ? String(parsed) : 'NULL';
}

const recipeId = input.recipe_id || input.id || '';
const videoId = input.video_id || input.videoId || '';
const docxUrl = input.nextcloud_docx_url || input.docx_share_link || input.docx_url || input.urls?.docx_url || '';
const pdfUrl = input.nextcloud_pdf_url || input.pdf_share_link || input.pdf_url || input.urls?.pdf_url || '';

const recipeIdSql = intOrNull(recipeId);
const videoIdSql = sqlQuote(videoId);
const docxUrlSql = sqlQuote(docxUrl);
const pdfUrlSql = sqlQuote(pdfUrl);

const findRecipeSql = `WITH input AS (
  SELECT ${recipeIdSql}::integer AS recipe_id,
         ${videoIdSql}::text AS video_id,
         ${docxUrlSql}::text AS input_docx_url,
         ${pdfUrlSql}::text AS input_pdf_url
), selected AS (
  SELECT r.*
  FROM recipes r, input i
  WHERE (i.recipe_id IS NOT NULL AND r.id = i.recipe_id)
     OR (i.video_id IS NOT NULL AND i.video_id <> '' AND r.video_id = i.video_id)
  ORDER BY r.updated_at DESC
  LIMIT 1
)
SELECT
  selected.id AS recipe_id,
  selected.video_id,
  selected.title,
  selected.category,
  selected.youtube_url,
  selected.youtube_channel,
  COALESCE(NULLIF(input.input_docx_url, ''), selected.nextcloud_docx_url, '') AS docx_url,
  COALESCE(NULLIF(input.input_pdf_url, ''), selected.nextcloud_pdf_url, '') AS pdf_url
FROM input
LEFT JOIN selected ON TRUE;`;

return [{ json: { recipe_id: recipeId, video_id: videoId, docx_url: docxUrl, pdf_url: pdfUrl, find_recipe_sql: findRecipeSql } }];

